    /// Returns the severity for availability rows.
    pub const fn severity(self) -> StatusSeverity {
        match self {
            Self::Installed => StatusSeverity::Good,
            Self::NotFound => StatusSeverity::Error,
            Self::Unknown => StatusSeverity::Unknown,
        }
    }
}

